spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 8000;
    var progress = (t % duration) / duration;

    var centerX1 = W / 2 - 45;
    var centerX2 = W / 2 + 45;
    var centerY = H / 2 + 10;
    var radius = 70;

    // Phase boundaries
    var p1 = 0.20; // 0 to 2s: draw empty circles
    var p2 = 0.60; // 2s to 6s: animate numbers flying into positions
    var p3 = 0.90; // 6s to 9s: highlight overlap and pulse 6

    // Draw Venn Circles
    ctx.lineWidth = 2.5;

    // Left Circle (12)
    ctx.strokeStyle = '#3B82F6';
    ctx.beginPath();
    ctx.arc(centerX1, centerY, radius, 0, Math.PI * 2);
    ctx.stroke();

    // Right Circle (18)
    ctx.strokeStyle = '#EC4899';
    ctx.beginPath();
    ctx.arc(centerX2, centerY, radius, 0, Math.PI * 2);
    ctx.stroke();

    // Labels above circles
    ctx.fillStyle = '#9CA3AF';
    ctx.font = '12px -apple-system, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('Factors of 12', centerX1 - 15, centerY - radius - 15);
    ctx.fillText('Factors of 18', centerX2 + 15, centerY - radius - 15);

    // Sorted factors data
    var items = [
      { val: 4, endX: centerX1 - 35, endY: centerY - 15, delay: 0.15 },
      { val: 12, endX: centerX1 - 35, endY: centerY + 15, delay: 0.22 },
      { val: 9, endX: centerX2 + 35, endY: centerY - 15, delay: 0.18 },
      { val: 18, endX: centerX2 + 35, endY: centerY + 15, delay: 0.25 },
      // Overlap
      { val: 1, endX: W / 2, endY: centerY - 40, delay: 0.30 },
      { val: 2, endX: W / 2, endY: centerY - 15, delay: 0.35 },
      { val: 3, endX: W / 2, endY: centerY + 10, delay: 0.40 },
      { val: 6, endX: W / 2, endY: centerY + 35, delay: 0.45, isGCD: true }
    ];

    // Draw elements
    for (var i = 0; i < items.length; i++) {
      var item = items[i];

      // Calculate fly-in transition
      var itemProgress = Math.max(0, Math.min(1.0, (progress - item.delay) / 0.2));
      var startX = item.val <= 12 && !item.isGCD && item.val !== 1 && item.val !== 2 && item.val !== 3 ? 30 : W - 30;
      if (item.val === 1 || item.val === 2 || item.val === 3 || item.isGCD) startX = W / 2;
      var startY = H - 25;

      var curX = startX + (item.endX - startX) * itemProgress;
      var curY = startY + (item.endY - startY) * itemProgress;

      if (progress > item.delay) {
        if (item.isGCD && progress >= p2) {
          // Glow / Pulse the GCD (6)
          var pulse = 1 + Math.sin(t * 0.015) * 0.15;
          ctx.fillStyle = '#10B981';
          ctx.font = 'bold ' + Math.floor(18 * pulse) + 'px -apple-system, sans-serif';
          ctx.fillText(item.val.toString(), curX, curY);

          // Draw small highlight ring
          ctx.strokeStyle = '#34D399';
          ctx.lineWidth = 1.5;
          ctx.beginPath();
          ctx.arc(curX, curY - 1, 12 * pulse, 0, Math.PI * 2);
          ctx.stroke();
        } else {
          ctx.fillStyle = (item.endX === W / 2) ? '#34D399' : '#F3F4F6'; // Green for common factors
          ctx.font = 'bold 14px -apple-system, sans-serif';
          ctx.fillText(item.val.toString(), curX, curY);
        }
      }
    }

    // Helper bottom text
    ctx.fillStyle = '#FBBF24';
    ctx.font = 'bold 16px -apple-system, sans-serif';
    if (progress < p1) {
      ctx.fillText('Analyzing factors...', W / 2, centerY - radius - 45);
    } else if (progress < p2) {
      ctx.fillText('Sorting factors into Venn Diagram', W / 2, centerY - radius - 45);
    } else {
      ctx.fillText('GCD(12, 18) = 6', W / 2, centerY - radius - 45);
    }
  }
};
